INSERT INTO public.kanji (level_id, kanji, hiragana, romaji, meaning, hint, stroke_count, examples, order_index) VALUES
(1, '一', 'いち・ひと', 'ichi / hito', 'Satu', 'Satu garis horizontal — angka paling sederhana, satu.', 1, '[{"kanji":"一つ","hiragana":"ひとつ","meaning":"satu (benda)"},{"kanji":"一人","hiragana":"ひとり","meaning":"satu orang"},{"kanji":"一月","hiragana":"いちがつ","meaning":"Januari"}]'::jsonb, 1),
(1, '二', 'に・ふた', 'ni / futa', 'Dua', 'Dua garis horizontal bertumpuk — angka dua.', 2, '[{"kanji":"二つ","hiragana":"ふたつ","meaning":"dua (benda)"},{"kanji":"二人","hiragana":"ふたり","meaning":"dua orang"},{"kanji":"二月","hiragana":"にがつ","meaning":"Februari"}]'::jsonb, 2),
(1, '三', 'さん・み', 'san / mi', 'Tiga', 'Tiga garis horizontal — angka tiga.', 3, '[{"kanji":"三つ","hiragana":"みっつ","meaning":"tiga (benda)"},{"kanji":"三人","hiragana":"さんにん","meaning":"tiga orang"},{"kanji":"三月","hiragana":"さんがつ","meaning":"Maret"}]'::jsonb, 3),
(1, '四', 'し・よん・よ', 'shi / yon / yo', 'Empat', 'Kotak dengan kaki di dalam — angka empat.', 5, '[{"kanji":"四つ","hiragana":"よっつ","meaning":"empat (benda)"},{"kanji":"四月","hiragana":"しがつ","meaning":"April"},{"kanji":"四人","hiragana":"よにん","meaning":"empat orang"}]'::jsonb, 4),
(1, '五', 'ご・いつ', 'go / itsu', 'Lima', 'Garis atas-bawah dengan zigzag di tengah — angka lima.', 4, '[{"kanji":"五つ","hiragana":"いつつ","meaning":"lima (benda)"},{"kanji":"五月","hiragana":"ごがつ","meaning":"Mei"},{"kanji":"五分","hiragana":"ごふん","meaning":"lima menit"}]'::jsonb, 5),
(1, '六', 'ろく・む', 'roku / mu', 'Enam', 'Tutup dengan dua kaki — angka enam.', 4, '[{"kanji":"六つ","hiragana":"むっつ","meaning":"enam (benda)"},{"kanji":"六月","hiragana":"ろくがつ","meaning":"Juni"},{"kanji":"六時","hiragana":"ろくじ","meaning":"jam enam"}]'::jsonb, 6),
(1, '七', 'しち・なな', 'shichi / nana', 'Tujuh', 'Seperti pisau melengkung — angka tujuh.', 2, '[{"kanji":"七つ","hiragana":"ななつ","meaning":"tujuh (benda)"},{"kanji":"七月","hiragana":"しちがつ","meaning":"Juli"},{"kanji":"七時","hiragana":"しちじ","meaning":"jam tujuh"}]'::jsonb, 7),
(1, '八', 'はち・や', 'hachi / ya', 'Delapan', 'Dua garis terbuka melebar ke bawah — angka delapan.', 2, '[{"kanji":"八つ","hiragana":"やっつ","meaning":"delapan (benda)"},{"kanji":"八月","hiragana":"はちがつ","meaning":"Agustus"},{"kanji":"八百屋","hiragana":"やおや","meaning":"toko sayur"}]'::jsonb, 8),
(1, '九', 'きゅう・く・ここの', 'kyuu / ku / kokono', 'Sembilan', 'Kail yang melengkung — angka sembilan.', 2, '[{"kanji":"九つ","hiragana":"ここのつ","meaning":"sembilan (benda)"},{"kanji":"九月","hiragana":"くがつ","meaning":"September"},{"kanji":"九時","hiragana":"くじ","meaning":"jam sembilan"}]'::jsonb, 9),
(1, '十', 'じゅう・とお', 'juu / too', 'Sepuluh', 'Tanda silang sempurna — angka sepuluh.', 2, '[{"kanji":"十","hiragana":"じゅう","meaning":"sepuluh"},{"kanji":"十月","hiragana":"じゅうがつ","meaning":"Oktober"},{"kanji":"二十歳","hiragana":"はたち","meaning":"umur 20 tahun"}]'::jsonb, 10),
(1, '百', 'ひゃく', 'hyaku', 'Seratus', 'Satu (一) di atas putih (白) — bilangan seratus.', 6, '[{"kanji":"百","hiragana":"ひゃく","meaning":"seratus"},{"kanji":"百円","hiragana":"ひゃくえん","meaning":"100 yen"},{"kanji":"三百","hiragana":"さんびゃく","meaning":"tiga ratus"}]'::jsonb, 11),
(1, '千', 'せん・ち', 'sen / chi', 'Seribu', 'Orang (人) di atas satu (十) — bilangan seribu.', 3, '[{"kanji":"千","hiragana":"せん","meaning":"seribu"},{"kanji":"千円","hiragana":"せんえん","meaning":"1000 yen"},{"kanji":"千葉","hiragana":"ちば","meaning":"Chiba (kota)"}]'::jsonb, 12),
(1, '万', 'まん・ばん', 'man / ban', 'Sepuluh ribu, Banyak', 'Simbol bilangan besar — sepuluh ribu.', 3, '[{"kanji":"一万","hiragana":"いちまん","meaning":"sepuluh ribu"},{"kanji":"万年筆","hiragana":"まんねんひつ","meaning":"pulpen"},{"kanji":"万一","hiragana":"まんいち","meaning":"seandainya"}]'::jsonb, 13),
(1, '円', 'えん・まる', 'en / maru', 'Yen, Lingkaran', 'Bingkai dengan isi — mata uang yen, juga berarti bulat.', 4, '[{"kanji":"円","hiragana":"えん","meaning":"yen"},{"kanji":"百円","hiragana":"ひゃくえん","meaning":"100 yen"},{"kanji":"円い","hiragana":"まるい","meaning":"bulat"}]'::jsonb, 14),
(1, '年', 'ねん・とし', 'nen / toshi', 'Tahun', 'Simbol panen padi — satu tahun penuh.', 6, '[{"kanji":"今年","hiragana":"ことし","meaning":"tahun ini"},{"kanji":"去年","hiragana":"きょねん","meaning":"tahun lalu"},{"kanji":"来年","hiragana":"らいねん","meaning":"tahun depan"}]'::jsonb, 15),
(1, '月', 'つき・がつ・げつ', 'tsuki / gatsu / getsu', 'Bulan', 'Bentuknya seperti bulan sabit dengan dua garis di dalamnya.', 4, '[{"kanji":"月曜日","hiragana":"げつようび","meaning":"hari Senin"},{"kanji":"一月","hiragana":"いちがつ","meaning":"bulan Januari"},{"kanji":"来月","hiragana":"らいげつ","meaning":"bulan depan"}]'::jsonb, 16),
(1, '日', 'にち・じつ・ひ', 'nichi / jitsu / hi', 'Hari, Matahari', 'Bayangkan matahari berbentuk kotak dengan garis di tengahnya.', 4, '[{"kanji":"今日","hiragana":"きょう","meaning":"hari ini"},{"kanji":"日曜日","hiragana":"にちようび","meaning":"hari Minggu"},{"kanji":"毎日","hiragana":"まいにち","meaning":"setiap hari"}]'::jsonb, 17),
(1, '時', 'じ・とき', 'ji / toki', 'Waktu, Jam', 'Matahari (日) + kuil (寺) — waktu yang diukur matahari.', 10, '[{"kanji":"時間","hiragana":"じかん","meaning":"waktu, jam"},{"kanji":"一時","hiragana":"いちじ","meaning":"jam satu"},{"kanji":"時計","hiragana":"とけい","meaning":"jam (alat)"}]'::jsonb, 18),
(1, '分', 'ふん・ぶん・わ', 'fun / bun / wa', 'Menit, Membagi', 'Pisau (刀) membagi (八) — membagi waktu jadi menit.', 4, '[{"kanji":"五分","hiragana":"ごふん","meaning":"lima menit"},{"kanji":"半分","hiragana":"はんぶん","meaning":"setengah"},{"kanji":"分かる","hiragana":"わかる","meaning":"mengerti"}]'::jsonb, 19),
(1, '週', 'しゅう', 'shuu', 'Minggu (pekan)', 'Bergerak (辶) mengelilingi (周) — siklus satu pekan.', 11, '[{"kanji":"今週","hiragana":"こんしゅう","meaning":"minggu ini"},{"kanji":"来週","hiragana":"らいしゅう","meaning":"minggu depan"},{"kanji":"週末","hiragana":"しゅうまつ","meaning":"akhir pekan"}]'::jsonb, 20),
(1, '間', 'あいだ・かん・ま', 'aida / kan / ma', 'Antara, Selang', 'Matahari (日) terlihat dari celah pintu (門) — ruang antara.', 12, '[{"kanji":"時間","hiragana":"じかん","meaning":"waktu"},{"kanji":"人間","hiragana":"にんげん","meaning":"manusia"},{"kanji":"間","hiragana":"あいだ","meaning":"antara"}]'::jsonb, 21),
(1, '今', 'いま・こん', 'ima / kon', 'Sekarang', 'Atap menutup sesuatu yang ada saat ini — sekarang.', 4, '[{"kanji":"今","hiragana":"いま","meaning":"sekarang"},{"kanji":"今日","hiragana":"きょう","meaning":"hari ini"},{"kanji":"今年","hiragana":"ことし","meaning":"tahun ini"}]'::jsonb, 22),
(1, '先', 'せん・さき', 'sen / saki', 'Sebelum, Ujung', 'Kaki melangkah duluan — yang lebih dahulu, ujung depan.', 6, '[{"kanji":"先生","hiragana":"せんせい","meaning":"guru"},{"kanji":"先週","hiragana":"せんしゅう","meaning":"minggu lalu"},{"kanji":"先に","hiragana":"さきに","meaning":"duluan"}]'::jsonb, 23),
(1, '来', 'く・き・らい', 'ku / ki / rai', 'Datang', 'Gandum matang yang dibawa datang — kedatangan.', 7, '[{"kanji":"来る","hiragana":"くる","meaning":"datang"},{"kanji":"来年","hiragana":"らいねん","meaning":"tahun depan"},{"kanji":"来週","hiragana":"らいしゅう","meaning":"minggu depan"}]'::jsonb, 24),
(1, '去', 'きょ・こ・さ', 'kyo / ko / sa', 'Pergi, Lampau', 'Tanah (土) dan sesuatu yang ditinggalkan — pergi, masa lalu.', 5, '[{"kanji":"去年","hiragana":"きょねん","meaning":"tahun lalu"},{"kanji":"過去","hiragana":"かこ","meaning":"masa lalu"},{"kanji":"去る","hiragana":"さる","meaning":"meninggalkan"}]'::jsonb, 25),
(1, '入', 'い・はい・にゅう', 'i / hai / nyuu', 'Masuk', 'Bentuk seperti pintu masuk — masuk ke dalam.', 2, '[{"kanji":"入る","hiragana":"はいる","meaning":"masuk"},{"kanji":"入口","hiragana":"いりぐち","meaning":"pintu masuk"},{"kanji":"入学","hiragana":"にゅうがく","meaning":"masuk sekolah"}]'::jsonb, 26),
(1, '出', 'で・だ・しゅつ', 'de / da / shutsu', 'Keluar', 'Tunas keluar dari tanah ke atas — keluar, muncul.', 5, '[{"kanji":"出る","hiragana":"でる","meaning":"keluar"},{"kanji":"出口","hiragana":"でぐち","meaning":"pintu keluar"},{"kanji":"出発","hiragana":"しゅっぱつ","meaning":"keberangkatan"}]'::jsonb, 27),
(1, '行', 'い・ゆ・こう・ぎょう', 'i / yu / kou / gyou', 'Pergi, Baris', 'Persimpangan jalan — orang berjalan pergi.', 6, '[{"kanji":"行く","hiragana":"いく","meaning":"pergi"},{"kanji":"銀行","hiragana":"ぎんこう","meaning":"bank"},{"kanji":"旅行","hiragana":"りょこう","meaning":"perjalanan"}]'::jsonb, 28),
(1, '見', 'み・けん', 'mi / ken', 'Melihat', 'Mata (目) di atas orang berdiri — orang sedang melihat.', 7, '[{"kanji":"見る","hiragana":"みる","meaning":"melihat"},{"kanji":"見せる","hiragana":"みせる","meaning":"memperlihatkan"},{"kanji":"意見","hiragana":"いけん","meaning":"pendapat"}]'::jsonb, 29),
(1, '聞', 'き・ぶん・もん', 'ki / bun / mon', 'Mendengar, Bertanya', 'Telinga (耳) di balik pintu (門) — mendengarkan.', 14, '[{"kanji":"聞く","hiragana":"きく","meaning":"mendengar, bertanya"},{"kanji":"新聞","hiragana":"しんぶん","meaning":"koran"},{"kanji":"見聞","hiragana":"けんぶん","meaning":"pengetahuan"}]'::jsonb, 30),
(1, '食', 'た・しょく', 'ta / shoku', 'Makan, Makanan', 'Atap dengan nasi di bawah — orang makan di bawah atap.', 9, '[{"kanji":"食べる","hiragana":"たべる","meaning":"makan"},{"kanji":"食事","hiragana":"しょくじ","meaning":"makan (formal)"},{"kanji":"食堂","hiragana":"しょくどう","meaning":"kantin"}]'::jsonb, 31),
(1, '飲', 'の・いん', 'no / in', 'Minum', 'Makan/minuman (食) + menganga (欠) — menenggak minuman.', 12, '[{"kanji":"飲む","hiragana":"のむ","meaning":"minum"},{"kanji":"飲み物","hiragana":"のみもの","meaning":"minuman"},{"kanji":"飲料水","hiragana":"いんりょうすい","meaning":"air minum"}]'::jsonb, 32),
(1, '買', 'か・ばい', 'ka / bai', 'Membeli', 'Jaring (网) dan uang (貝) — menangkap barang dengan uang.', 12, '[{"kanji":"買う","hiragana":"かう","meaning":"membeli"},{"kanji":"買い物","hiragana":"かいもの","meaning":"belanja"},{"kanji":"売買","hiragana":"ばいばい","meaning":"jual beli"}]'::jsonb, 33),
(1, '売', 'う・ばい', 'u / bai', 'Menjual', 'Barang dikeluarkan untuk ditukar uang — menjual.', 7, '[{"kanji":"売る","hiragana":"うる","meaning":"menjual"},{"kanji":"売り場","hiragana":"うりば","meaning":"area penjualan"},{"kanji":"発売","hiragana":"はつばい","meaning":"perilisan"}]'::jsonb, 34),
(1, '書', 'か・しょ', 'ka / sho', 'Menulis', 'Kuas (聿) menulis di atas kertas — menulis.', 10, '[{"kanji":"書く","hiragana":"かく","meaning":"menulis"},{"kanji":"辞書","hiragana":"じしょ","meaning":"kamus"},{"kanji":"図書館","hiragana":"としょかん","meaning":"perpustakaan"}]'::jsonb, 35),
(1, '読', 'よ・どく', 'yo / doku', 'Membaca', 'Ucapan (言) + menjual (売) — menyuarakan tulisan, membaca.', 14, '[{"kanji":"読む","hiragana":"よむ","meaning":"membaca"},{"kanji":"読書","hiragana":"どくしょ","meaning":"membaca buku"},{"kanji":"音読み","hiragana":"おんよみ","meaning":"bacaan on"}]'::jsonb, 36),
(1, '話', 'はな・わ', 'hana / wa', 'Berbicara, Cerita', 'Ucapan (言) + lidah (舌) — berbicara dengan lidah.', 13, '[{"kanji":"話す","hiragana":"はなす","meaning":"berbicara"},{"kanji":"電話","hiragana":"でんわ","meaning":"telepon"},{"kanji":"会話","hiragana":"かいわ","meaning":"percakapan"}]'::jsonb, 37),
(1, '待', 'ま・たい', 'ma / tai', 'Menunggu', 'Berjalan (彳) ke kuil (寺) lalu menunggu — menunggu.', 9, '[{"kanji":"待つ","hiragana":"まつ","meaning":"menunggu"},{"kanji":"待合室","hiragana":"まちあいしつ","meaning":"ruang tunggu"},{"kanji":"期待","hiragana":"きたい","meaning":"harapan"}]'::jsonb, 38),
(1, '使', 'つか・し', 'tsuka / shi', 'Memakai, Utusan', 'Orang (亻) + pejabat (吏) — menyuruh memakai, utusan.', 8, '[{"kanji":"使う","hiragana":"つかう","meaning":"memakai"},{"kanji":"使い方","hiragana":"つかいかた","meaning":"cara pakai"},{"kanji":"大使館","hiragana":"たいしかん","meaning":"kedutaan"}]'::jsonb, 39),
(1, '始', 'はじ・し', 'haji / shi', 'Memulai', 'Wanita (女) melahirkan awal (台) — memulai sesuatu.', 8, '[{"kanji":"始める","hiragana":"はじめる","meaning":"memulai"},{"kanji":"始まる","hiragana":"はじまる","meaning":"dimulai"},{"kanji":"開始","hiragana":"かいし","meaning":"permulaan"}]'::jsonb, 40),
(1, '終', 'お・しゅう', 'o / shuu', 'Selesai, Akhir', 'Benang (糸) + musim dingin (冬) — akhir, penutup.', 11, '[{"kanji":"終わる","hiragana":"おわる","meaning":"selesai"},{"kanji":"終電","hiragana":"しゅうでん","meaning":"kereta terakhir"},{"kanji":"最終","hiragana":"さいしゅう","meaning":"paling akhir"}]'::jsonb, 41),
(1, '帰', 'かえ・き', 'kae / ki', 'Pulang', 'Kembali ke tempat asal — pulang ke rumah.', 10, '[{"kanji":"帰る","hiragana":"かえる","meaning":"pulang"},{"kanji":"帰国","hiragana":"きこく","meaning":"pulang ke negara asal"},{"kanji":"帰り","hiragana":"かえり","meaning":"perjalanan pulang"}]'::jsonb, 42),
(1, '休', 'やす・きゅう', 'yasu / kyuu', 'Istirahat, Libur', 'Orang (亻) bersandar pohon (木) — istirahat.', 6, '[{"kanji":"休む","hiragana":"やすむ","meaning":"istirahat"},{"kanji":"休み","hiragana":"やすみ","meaning":"libur"},{"kanji":"休日","hiragana":"きゅうじつ","meaning":"hari libur"}]'::jsonb, 43),
(1, '寝', 'ね・しん', 'ne / shin', 'Tidur', 'Atap rumah (宀) tempat orang berbaring — tidur.', 13, '[{"kanji":"寝る","hiragana":"ねる","meaning":"tidur"},{"kanji":"寝室","hiragana":"しんしつ","meaning":"kamar tidur"},{"kanji":"昼寝","hiragana":"ひるね","meaning":"tidur siang"}]'::jsonb, 44),
(1, '起', 'お・き', 'o / ki', 'Bangun, Bangkit', 'Berlari (走) lalu berdiri (己) — bangun, bangkit.', 10, '[{"kanji":"起きる","hiragana":"おきる","meaning":"bangun"},{"kanji":"起こす","hiragana":"おこす","meaning":"membangunkan"},{"kanji":"起立","hiragana":"きりつ","meaning":"berdiri tegak"}]'::jsonb, 45),
(1, '立', 'た・りつ', 'ta / ritsu', 'Berdiri', 'Orang berdiri di atas tanah — berdiri tegak.', 5, '[{"kanji":"立つ","hiragana":"たつ","meaning":"berdiri"},{"kanji":"国立","hiragana":"こくりつ","meaning":"negeri (milik negara)"},{"kanji":"立派","hiragana":"りっぱ","meaning":"hebat, megah"}]'::jsonb, 46),
(1, '座', 'すわ・ざ', 'suwa / za', 'Duduk', 'Dua orang (人人) di tanah di bawah atap — duduk.', 10, '[{"kanji":"座る","hiragana":"すわる","meaning":"duduk"},{"kanji":"座席","hiragana":"ざせき","meaning":"tempat duduk"},{"kanji":"正座","hiragana":"せいざ","meaning":"duduk bersimpuh"}]'::jsonb, 47),
(1, '走', 'はし・そう', 'hashi / sou', 'Berlari', 'Orang dengan kaki bergerak cepat — berlari.', 7, '[{"kanji":"走る","hiragana":"はしる","meaning":"berlari"},{"kanji":"競走","hiragana":"きょうそう","meaning":"lomba lari"},{"kanji":"走者","hiragana":"そうしゃ","meaning":"pelari"}]'::jsonb, 48),
(1, '歩', 'ある・ほ・ぶ', 'aru / ho / bu', 'Berjalan', 'Berhenti (止) lalu melangkah sedikit — berjalan kaki.', 8, '[{"kanji":"歩く","hiragana":"あるく","meaning":"berjalan"},{"kanji":"散歩","hiragana":"さんぽ","meaning":"jalan-jalan"},{"kanji":"歩道","hiragana":"ほどう","meaning":"trotoar"}]'::jsonb, 49),
(1, '泳', 'およ・えい', 'oyo / ei', 'Berenang', 'Air (氵) + selamanya (永) — bergerak terus di air, berenang.', 8, '[{"kanji":"泳ぐ","hiragana":"およぐ","meaning":"berenang"},{"kanji":"水泳","hiragana":"すいえい","meaning":"renang"},{"kanji":"泳ぎ","hiragana":"およぎ","meaning":"renang (kata benda)"}]'::jsonb, 50),
(1, '働', 'はたら・どう', 'hatara / dou', 'Bekerja', 'Orang (亻) bergerak (動) — orang yang bekerja.', 13, '[{"kanji":"働く","hiragana":"はたらく","meaning":"bekerja"},{"kanji":"労働","hiragana":"ろうどう","meaning":"tenaga kerja"},{"kanji":"共働き","hiragana":"ともばたらき","meaning":"suami-istri bekerja"}]'::jsonb, 51),
(1, '勉', 'べん', 'ben', 'Berusaha (belajar)', 'Mengerahkan tenaga (力) keras — berusaha dalam belajar.', 10, '[{"kanji":"勉強","hiragana":"べんきょう","meaning":"belajar"},{"kanji":"勤勉","hiragana":"きんべん","meaning":"rajin"},{"kanji":"勉学","hiragana":"べんがく","meaning":"studi"}]'::jsonb, 52),
(1, '強', 'つよ・きょう・ごう', 'tsuyo / kyou / gou', 'Kuat', 'Busur (弓) yang kuat dengan serangga (虫) — kekuatan.', 11, '[{"kanji":"強い","hiragana":"つよい","meaning":"kuat"},{"kanji":"勉強","hiragana":"べんきょう","meaning":"belajar"},{"kanji":"強力","hiragana":"きょうりょく","meaning":"bertenaga"}]'::jsonb, 53),
(1, '習', 'なら・しゅう', 'nara / shuu', 'Mempelajari, Latihan', 'Sayap (羽) + diri (白) — burung berlatih terbang, belajar.', 11, '[{"kanji":"習う","hiragana":"ならう","meaning":"mempelajari"},{"kanji":"練習","hiragana":"れんしゅう","meaning":"latihan"},{"kanji":"学習","hiragana":"がくしゅう","meaning":"pembelajaran"}]'::jsonb, 54),
(1, '教', 'おし・きょう', 'oshi / kyou', 'Mengajar', 'Tangan mendorong (攵) anak belajar — mengajar.', 11, '[{"kanji":"教える","hiragana":"おしえる","meaning":"mengajar"},{"kanji":"教室","hiragana":"きょうしつ","meaning":"ruang kelas"},{"kanji":"宗教","hiragana":"しゅうきょう","meaning":"agama"}]'::jsonb, 55),
(1, '大', 'おお・だい・たい', 'oo / dai / tai', 'Besar', 'Orang berdiri dengan tangan lebar terbuka — sesuatu yang besar.', 3, '[{"kanji":"大学","hiragana":"だいがく","meaning":"universitas"},{"kanji":"大きい","hiragana":"おおきい","meaning":"besar"},{"kanji":"大丈夫","hiragana":"だいじょうぶ","meaning":"tidak apa-apa"}]'::jsonb, 56),
(1, '小', 'ちい・しょう・こ', 'chii / shou / ko', 'Kecil', 'Satu garis tengah dengan dua titik kecil di sisi — kecil.', 3, '[{"kanji":"小学校","hiragana":"しょうがっこう","meaning":"sekolah dasar"},{"kanji":"小さい","hiragana":"ちいさい","meaning":"kecil"},{"kanji":"小川","hiragana":"おがわ","meaning":"sungai kecil"}]'::jsonb, 57),
(1, '高', 'たか・こう', 'taka / kou', 'Tinggi, Mahal', 'Gambar bangunan menara tinggi — tinggi, mahal.', 10, '[{"kanji":"高い","hiragana":"たかい","meaning":"tinggi, mahal"},{"kanji":"高校","hiragana":"こうこう","meaning":"SMA"},{"kanji":"高速","hiragana":"こうそく","meaning":"kecepatan tinggi"}]'::jsonb, 58),
(1, '安', 'やす・あん', 'yasu / an', 'Murah, Tenang', 'Wanita (女) di bawah atap (宀) — rumah yang tenang, aman, murah.', 6, '[{"kanji":"安い","hiragana":"やすい","meaning":"murah"},{"kanji":"安心","hiragana":"あんしん","meaning":"lega, tenang"},{"kanji":"安全","hiragana":"あんぜん","meaning":"keselamatan"}]'::jsonb, 59),
(1, '新', 'あたら・しん', 'atara / shin', 'Baru', 'Pohon (木) dipotong kapak (斤) untuk kayu baru — baru.', 13, '[{"kanji":"新しい","hiragana":"あたらしい","meaning":"baru"},{"kanji":"新聞","hiragana":"しんぶん","meaning":"koran"},{"kanji":"新幹線","hiragana":"しんかんせん","meaning":"shinkansen"}]'::jsonb, 60),
(1, '古', 'ふる・こ', 'furu / ko', 'Lama, Tua', 'Sepuluh (十) mulut (口) generasi — sesuatu yang sudah lama.', 5, '[{"kanji":"古い","hiragana":"ふるい","meaning":"lama, tua"},{"kanji":"中古","hiragana":"ちゅうこ","meaning":"bekas"},{"kanji":"古本","hiragana":"ふるほん","meaning":"buku bekas"}]'::jsonb, 61),
