(1, '少', 'すく・すこ・しょう', 'suku / suko / shou', 'Sedikit', 'Kecil (小) dengan satu garis terpotong — semakin sedikit.', 4, '[{"kanji":"少ない","hiragana":"すくない","meaning":"sedikit"},{"kanji":"少し","hiragana":"すこし","meaning":"sedikit"},{"kanji":"少年","hiragana":"しょうねん","meaning":"anak laki-laki"}]'::jsonb, 65),
