(1, '黒', 'くろ・こく', 'kuro / koku', 'Hitam', 'Tungku dengan jelaga — warna hitam.', 11, '[{"kanji":"黒い","hiragana":"くろい","meaning":"hitam"},{"kanji":"黒板","hiragana":"こくばん","meaning":"papan tulis"},{"kanji":"真っ黒","hiragana":"まっくろ","meaning":"hitam pekat"}]'::jsonb, 75),
