(1, '私', 'わたし・し', 'watashi / shi', 'Saya, Pribadi', 'Padi (禾) + diri (ム) — milik pribadiku, yaitu saya.', 7, '[{"kanji":"私","hiragana":"わたし","meaning":"saya"},{"kanji":"私立","hiragana":"しりつ","meaning":"swasta"},{"kanji":"私服","hiragana":"しふく","meaning":"pakaian pribadi"}]'::jsonb, 78),
