(1, '男', 'おとこ・だん・なん', 'otoko / dan / nan', 'Laki-laki', 'Sawah (田) + tenaga (力) — yang bertenaga di sawah, laki-laki.', 7, '[{"kanji":"男","hiragana":"おとこ","meaning":"laki-laki"},{"kanji":"男性","hiragana":"だんせい","meaning":"pria"},{"kanji":"長男","hiragana":"ちょうなん","meaning":"anak laki tertua"}]'::jsonb, 80),
