(1, '兄', 'あに・きょう・けい', 'ani / kyou / kei', 'Kakak laki-laki', 'Mulut (口) di atas orang (儿) — yang lebih dewasa, kakak.', 5, '[{"kanji":"兄","hiragana":"あに","meaning":"kakak laki (sendiri)"},{"kanji":"お兄さん","hiragana":"おにいさん","meaning":"kakak laki (sopan)"},{"kanji":"兄弟","hiragana":"きょうだい","meaning":"saudara"}]'::jsonb, 85),
(1, '弟', 'おとうと・てい・だい', 'otouto / tei / dai', 'Adik laki-laki', 'Urutan yang lebih muda — adik laki-laki.', 7, '[{"kanji":"弟","hiragana":"おとうと","meaning":"adik laki"},{"kanji":"兄弟","hiragana":"きょうだい","meaning":"saudara"},{"kanji":"弟子","hiragana":"でし","meaning":"murid"}]'::jsonb, 86),
