(1, '上', 'うえ・じょう・あ・のぼ', 'ue / jou / a / nobo', 'Atas', 'Garis bawah sebagai dasar, garis atas menunjuk ke langit.', 3, '[{"kanji":"上手","hiragana":"じょうず","meaning":"pandai"},{"kanji":"上","hiragana":"うえ","meaning":"di atas"},{"kanji":"上がる","hiragana":"あがる","meaning":"naik"}]'::jsonb, 97),
