(1, '手', 'て・しゅ', 'te / shu', 'Tangan', 'Empat jari dan ibu jari dengan pergelangan — tangan.', 4, '[{"kanji":"手","hiragana":"て","meaning":"tangan"},{"kanji":"上手","hiragana":"じょうず","meaning":"pandai"},{"kanji":"手紙","hiragana":"てがみ","meaning":"surat"}]'::jsonb, 101),
