INSERT INTO public.kanji (level_id, kanji, hiragana, romaji, meaning, hint, stroke_count, examples, order_index) VALUES
(2, '会', 'かい・あ', 'kai / a', 'Bertemu, Rapat', 'Orang berkumpul di bawah atap — bertemu, pertemuan.', 6, '[{"kanji":"会う","hiragana":"あう","meaning":"bertemu"},{"kanji":"会社","hiragana":"かいしゃ","meaning":"perusahaan"},{"kanji":"会議","hiragana":"かいぎ","meaning":"rapat"}]'::jsonb, 1),
