(2, '門', 'もん・かど', 'mon / kado', 'Gerbang', 'Dua daun pintu besar — gerbang.', 8, '[{"kanji":"門","hiragana":"もん","meaning":"gerbang"},{"kanji":"専門","hiragana":"せんもん","meaning":"spesialisasi"},{"kanji":"入門","hiragana":"にゅうもん","meaning":"pengantar"}]'::jsonb, 4),
(2, '紙', 'かみ・し', 'kami / shi', 'Kertas', 'Benang (糸) + akar (氏) — serat ditekan jadi kertas.', 10, '[{"kanji":"紙","hiragana":"かみ","meaning":"kertas"},{"kanji":"手紙","hiragana":"てがみ","meaning":"surat"},{"kanji":"新聞紙","hiragana":"しんぶんし","meaning":"kertas koran"}]'::jsonb, 5),
(2, '画', 'が・かく', 'ga / kaku', 'Gambar, Goresan', 'Bingkai dengan sawah di dalam — lukisan, rencana.', 8, '[{"kanji":"映画","hiragana":"えいが","meaning":"film"},{"kanji":"計画","hiragana":"けいかく","meaning":"rencana"},{"kanji":"画面","hiragana":"がめん","meaning":"layar"}]'::jsonb, 6),
(2, '映', 'えい・うつ・は', 'ei / utsu / ha', 'Memantulkan, Tayang', 'Matahari (日) menyinari pusat (央) — memantulkan, menayangkan.', 9, '[{"kanji":"映画","hiragana":"えいが","meaning":"film"},{"kanji":"映る","hiragana":"うつる","meaning":"terpantul"},{"kanji":"上映","hiragana":"じょうえい","meaning":"penayangan"}]'::jsonb, 7),
(2, '音', 'おと・おん・ね', 'oto / on / ne', 'Suara, Bunyi', 'Berdiri (立) di atas matahari (日) — getaran suara.', 9, '[{"kanji":"音","hiragana":"おと","meaning":"suara"},{"kanji":"音楽","hiragana":"おんがく","meaning":"musik"},{"kanji":"発音","hiragana":"はつおん","meaning":"pelafalan"}]'::jsonb, 8),
(2, '楽', 'たの・がく・らく', 'tano / gaku / raku', 'Senang, Musik', 'Pohon dengan hiasan benang — kegembiraan, musik.', 13, '[{"kanji":"楽しい","hiragana":"たのしい","meaning":"menyenangkan"},{"kanji":"音楽","hiragana":"おんがく","meaning":"musik"},{"kanji":"楽","hiragana":"らく","meaning":"nyaman, mudah"}]'::jsonb, 9),
(2, '料', 'りょう', 'ryou', 'Bahan, Biaya', 'Beras (米) ditakar (斗) — bahan dan ongkos.', 10, '[{"kanji":"料理","hiragana":"りょうり","meaning":"masakan"},{"kanji":"料金","hiragana":"りょうきん","meaning":"biaya"},{"kanji":"材料","hiragana":"ざいりょう","meaning":"bahan baku"}]'::jsonb, 10),
(2, '理', 'り・ことわり', 'ri / kotowari', 'Logika, Mengatur', 'Permata (王) disusun di sawah (里) — menata, logika.', 11, '[{"kanji":"料理","hiragana":"りょうり","meaning":"masakan"},{"kanji":"理由","hiragana":"りゆう","meaning":"alasan"},{"kanji":"無理","hiragana":"むり","meaning":"mustahil, memaksakan"}]'::jsonb, 11),
(2, '計', 'けい・はか', 'kei / haka', 'Menghitung, Rencana', 'Ucapan (言) + sepuluh (十) — menghitung, merencanakan.', 9, '[{"kanji":"計画","hiragana":"けいかく","meaning":"rencana"},{"kanji":"時計","hiragana":"とけい","meaning":"jam"},{"kanji":"合計","hiragana":"ごうけい","meaning":"jumlah total"}]'::jsonb, 12),
(2, '駅', 'えき', 'eki', 'Stasiun', 'Kuda (馬) + ukuran (尺) — tempat ganti kuda dulu, kini stasiun.', 14, '[{"kanji":"駅","hiragana":"えき","meaning":"stasiun"},{"kanji":"駅前","hiragana":"えきまえ","meaning":"depan stasiun"},{"kanji":"終着駅","hiragana":"しゅうちゃくえき","meaning":"stasiun terakhir"}]'::jsonb, 13),
(2, '店', 'みせ・てん', 'mise / ten', 'Toko', 'Atap (广) tempat menyimpan (占) barang — toko.', 8, '[{"kanji":"店","hiragana":"みせ","meaning":"toko"},{"kanji":"店員","hiragana":"てんいん","meaning":"pelayan toko"},{"kanji":"喫茶店","hiragana":"きっさてん","meaning":"kafe"}]'::jsonb, 14),
(2, '病', 'びょう・やまい', 'byou / yamai', 'Penyakit', 'Orang sakit di tempat tidur — penyakit.', 10, '[{"kanji":"病気","hiragana":"びょうき","meaning":"penyakit"},{"kanji":"病院","hiragana":"びょういん","meaning":"rumah sakit"},{"kanji":"急病","hiragana":"きゅうびょう","meaning":"sakit mendadak"}]'::jsonb, 15),
